<script setup lang="ts">
import {
    darkenColor,
    lightenColor,
    blendWithBg,
} from "~/assets/utils/shared/colors";

const { activeSettings } = useSettings();

const colors = computed(() => {
    const land = activeSettings.value?.landColor ?? "#60708e";
    const road = activeSettings.value?.roadColor ?? "#20324a";
    const water = activeSettings.value?.backgroundColor ?? "#24467b";
    const theme = activeSettings.value?.themeColor;

    return {
        water: water,
        land: land,
        landOutline: activeSettings.value?.landColor
            ? darkenColor(land, 0.2)
            : "#4e5e7d",
        roads: road,
        prefabLight: blendWithBg(lightenColor(theme, 0.3), 0.6),
        prefabDark: blendWithBg(lightenColor(theme, 0), 0.6),
    };
});
